function parsePayload(payload) {
    if (!payload) return null;
    if (typeof payload === "string") {
        try { return JSON.parse(payload); } catch (err) { return null; }
    }
    if (Buffer.isBuffer(payload)) {
        try { return JSON.parse(payload.toString()); } catch (err) { return null; }
    }
    return typeof payload === "object" ? payload : null;
}

const payload = parsePayload(msg.payload);
const acsmId = "acsm2";

if (!payload || payload.messageType !== "supply_chain_feedback") {
    node.warn("Invalid supply_chain_feedback payload ignored.");
    return null;
}

msg.topic = "acsm2/chain/feedback";
msg.payload = {
    schemaVersion: payload.schemaVersion || "1.0",
    messageType: "normalized_supply_chain_feedback",
    source: payload.source || "supply_chain",
    target: acsmId,
    ts: payload.ts || Date.now(),
    timestamp: payload.timestamp || new Date().toISOString(),
    correlationId: payload.correlationId || "",
    globalAssessment: payload.globalAssessment || null,
    globalDirectives: payload.globalDirectives || null,
    local: payload.perACSMFeedback ? payload.perACSMFeedback[acsmId] || null : null,
    raw: payload
};

return msg;
